                titlePadding ?? { top: 24, left: 24, right: 24, bottom: 16 },
                "padding",
              ) as React.CSSProperties
            }
          >
            {title}
          </div>
        )}
        {content && (
          <div
            className="text-sm text-muted-foreground"
            style={
              edgeInsetsToStyle(
