          <div
            className="flex items-center justify-end gap-2"
            style={
              edgeInsetsToStyle(
                actionsPadding ?? { left: 24, right: 24, bottom: 16 },
                "padding",
              ) as React.CSSProperties
            }
          >
            {actions.map((action, i) => (
