        : undefined;

    return (
      <div
        ref={ref}
        className={cn("grid overflow-y-auto", className)}
        style={{
          gridTemplateColumns,
          rowGap:
            typeof mainAxisSpacing === "number"
              ? `${mainAxisSpacing}px`
