export interface SidebarProps extends React.HTMLAttributes<HTMLDivElement> {
  isOpen: boolean;
  onClose: () => void;
  width?: string | number;
  position?: "left" | "right";
  key?: React.Key;
}

/**
 * A Flutter-style Drawer / Sidebar component.
 * Slides in from the edge of the screen and includes a backdrop.
 */
export const Sidebar = ({
  isOpen,
  onClose,
  width = 304, // Default Material drawer width
  position = "left",
  className,
  children,
  ...props
}: SidebarProps) => {
  // Prevent scrolling on the body when the sidebar is open
  React.useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }
    return () => {
      document.body.style.overflow = "auto";
    };
  }, [isOpen]);

  const transformClass =
    position === "left"
      ? isOpen
        ? "translate-x-0"
        : "-translate-x-full"
      : isOpen
        ? "translate-x-0"
        : "translate-x-full";

  return (
    <>
      {/* Backdrop */}
      <div
        className={cn(
          "fixed inset-0 z-[100] bg-black/50 transition-opacity duration-300",
          isOpen
            ? "opacity-100 pointer-events-auto"
            : "opacity-0 pointer-events-none",
        )}
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Sidebar Panel */}
      <div
        className={cn(
          "fixed top-0 bottom-0 z-[110] flex flex-col bg-background shadow-2xl transition-transform duration-300 ease-in-out pointer-events-auto",
          position === "left" ? "left-0" : "right-0",
          transformClass,
          className,
        )}
        style={{ width: typeof width === "number" ? `${width}px` : width }}
        {...props}
      >
        {children}
      </div>
    </>
  );
};

export const SidebarHeader = ({
