import * as React from "react";
import { cn } from "../utils";
import { Input } from "./input";
import { Label } from "./label";
import type { Color, EdgeInsetsInput, InputBorderInput } from "./flutter-style";
import { edgeInsetsToStyle, inputBorderToStyle } from "./flutter-style";

export type TextInputType =
  | "text"
  | "number"
  | "email"
  | "password"
  | "tel"
  | "url"
  | "search"
  | "multiline";

// ─── Text style types (mirrors text.tsx) ─────────────────────────────────────
type FontWeight =
  | "thin"
  | "extraLight"
  | "light"
  | "normal"
  | "medium"
  | "semiBold"
  | "bold"
  | "extraBold"
  | "black"
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900;
type TextOverflow = "ellipsis" | "clip" | "visible" | "fade";
type TextAlign = "left" | "center" | "right" | "justify" | "start" | "end";
type FontStyle = "normal" | "italic";
type TextDecoration = "none" | "underline" | "line-through" | "overline";

const fontWeightMap: Record<string, string> = {
  thin: "100",
  extraLight: "200",
  light: "300",
  normal: "400",
  medium: "500",
  semiBold: "600",
  bold: "700",
  extraBold: "800",
  black: "900",
};
const resolveFontWeight = (w?: FontWeight): string | undefined => {
  if (w === undefined) return undefined;
  if (typeof w === "number") return String(w);
  return fontWeightMap[w] ?? String(w);
};

export interface TextFieldProps extends Omit<
  React.InputHTMLAttributes<HTMLInputElement>,
  "type"
> {
  /** Label text shown above the field. */
  label?: string;
  /** Placeholder text inside the field. Equivalent to Flutter's hintText. */
  hintText?: string;
  /** Error message shown below the field. */
  errorText?: string;
  /** Helper message shown below the field (when no error). */
  helperText?: string;
  /** Widget shown inside the field at the start. */
  prefixIcon?: React.ReactNode;
  /** Widget shown inside the field at the end. */
  suffixIcon?: React.ReactNode;
  /** Text shown at the start of the field (e.g. "$"). */
  prefixText?: string;
  /** Text shown at the end of the field (e.g. ".com"). */
  suffixText?: string;
  /** Whether the field text is obscured (password). */
  obscureText?: boolean;
  /** Controls keyboard/input type. */
  keyboardType?: TextInputType;
  /** Max number of characters. */
  maxLength?: number;
  /** Max number of lines for multiline. */
  maxLines?: number;
  /** Min number of lines for multiline. */
  minLines?: number;
  /** Whether the field is read-only. */
  readOnly?: boolean;
  /** Whether the field is enabled. */
  enabled?: boolean;
  /** Whether to auto-focus. */
  autofocus?: boolean;
  /** Whether to fill the background. */
  filled?: boolean;
  /** Fill color when filled is true. */
  fillColor?: Color;
  /** Border radius of the field. */
  borderRadius?: number;
  /** Padding inside the field. */
  contentPadding?: EdgeInsetsInput;
  /** Called on value change. Equivalent to Flutter's onChanged. */
  onChanged?: (value: string) => void;
  /** Called when editing is complete (Enter pressed). */
  onEditingComplete?: () => void;
  /** Called when the field is submitted. */
  onFieldSubmitted?: (value: string) => void;
  // ─── Border decoration (mirrors Flutter InputDecoration) ───
  /** Default border for all states (fallback). Use InputBorder.none/outline/underline. */
  border?: InputBorderInput;
  /** Border when enabled and not focused. */
  enabledBorder?: InputBorderInput;
  /** Border when focused. */
  focusedBorder?: InputBorderInput;
  /** Border when disabled. */
  disabledBorder?: InputBorderInput;
  /** Border when errorText is set. */
  errorBorder?: InputBorderInput;
  /** Border when errorText is set and focused. */
  focusedErrorBorder?: InputBorderInput;
  // ─── Text style (mirrors Text component) ──────────────────
  /** Font size in px or CSS unit. */
  fontSize?: number | string;
  /** Font weight. Accepts Flutter-style names or numeric values. */
  fontWeight?: FontWeight;
  /** Text color. */
  color?: Color;
  /** Letter spacing in px or CSS unit. */
  letterSpacing?: number | string;
  /** Line height multiplier or px/unit string. */
  lineHeight?: number | string;
  /** Text decoration. */
  decoration?: TextDecoration;
  /** How to handle text that overflows. */
  overflow?: TextOverflow;
  /** Whether text wraps. false = single line. */
  softWrap?: boolean;
  /** Text alignment. */
  textAlign?: TextAlign;
  /** Font style. */
  fontStyle?: FontStyle;
  /** Opacity (0.0–1.0). */
  opacity?: number;
  className?: string;
  key?: React.Key;
}

/**
 * A text field for capturing user input.
 * Equivalent to Flutter's TextField() widget.
 */
export const TextField = React.forwardRef<HTMLInputElement, TextFieldProps>(
  (
    {
      label,
      hintText,
      errorText,
      helperText,
      prefixIcon,
      suffixIcon,
      prefixText,
      suffixText,
      obscureText,
      keyboardType = "text",
      maxLength,
      maxLines,
      minLines,
      readOnly,
      enabled = true,
      autofocus,
      filled = false,
      fillColor,
      borderRadius = 8,
      contentPadding,
      onChanged,
      onEditingComplete,
      onFieldSubmitted,
      border,
      enabledBorder,
      focusedBorder,
      disabledBorder,
      errorBorder,
      focusedErrorBorder,
      fontSize,
      fontWeight,
      color,
      letterSpacing,
      lineHeight,
      decoration,
      overflow,
      softWrap,
      textAlign,
      fontStyle,
      opacity,
      className,
      id,
      style,
      ...props
    },
    ref,
  ) => {
    const generatedId = React.useId();
    const inputId = id ?? generatedId;
    const isMultiline =
      keyboardType === "multiline" || (maxLines !== undefined && maxLines > 1);

    // ─── Border state (mirrors Flutter focus-aware decoration) ─
    const [isFocused, setIsFocused] = React.useState(false);
    const hasBorderOverride = !!(
      border ??
      enabledBorder ??
      focusedBorder ??
      disabledBorder ??
      errorBorder ??
      focusedErrorBorder
    );
    const activeBorder = React.useMemo<InputBorderInput | undefined>(() => {
      if (!hasBorderOverride) return undefined;
      if (!enabled) return disabledBorder ?? border;
      if (errorText)
        return isFocused
          ? (focusedErrorBorder ?? errorBorder ?? border)
          : (errorBorder ?? border);
      return isFocused ? (focusedBorder ?? border) : (enabledBorder ?? border);
    }, [
      isFocused,
      enabled,
      errorText,
      border,
      enabledBorder,
      focusedBorder,
      disabledBorder,
      errorBorder,
      focusedErrorBorder,
      hasBorderOverride,
    ]);
    const borderStyle = hasBorderOverride
      ? inputBorderToStyle(activeBorder)
      : {};

    const inputType = obscureText
      ? "password"
      : keyboardType === "email"
        ? "email"
        : keyboardType === "number"
          ? "number"
          : keyboardType === "tel"
            ? "tel"
            : keyboardType === "url"
              ? "url"
              : keyboardType === "search"
                ? "search"
                : "text";

    const textStyle: React.CSSProperties = {
      fontSize:
        fontSize !== undefined
          ? typeof fontSize === "number"
            ? `${fontSize}px`
            : fontSize
          : undefined,
      fontWeight: resolveFontWeight(fontWeight),
      color,
      letterSpacing:
        letterSpacing !== undefined
          ? typeof letterSpacing === "number"
            ? `${letterSpacing}px`
            : letterSpacing
          : undefined,
      lineHeight: lineHeight !== undefined ? lineHeight : undefined,
      textDecoration: decoration,
      textAlign,
      fontStyle,
      opacity,
    };

    const sharedStyle: React.CSSProperties = {
      borderRadius: `${borderRadius}px`,
      backgroundColor: filled ? fillColor : undefined,
      ...edgeInsetsToStyle(contentPadding, "padding"),
      ...style,
    };

    return (
      <div className={cn("grid w-full items-center gap-1.5", className)}>
        {label && <Label htmlFor={inputId}>{label}</Label>}
        <div className="relative">
          {prefixText && (
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">
              {prefixText}
            </span>
          )}
          {prefixIcon && !prefixText && (
            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground">
              {prefixIcon}
            </div>
          )}

          {isMultiline ? (
            <textarea
              id={inputId}
              ref={ref as React.Ref<HTMLTextAreaElement>}
              placeholder={hintText}
              readOnly={readOnly}
              disabled={!enabled}
              autoFocus={autofocus}
              maxLength={maxLength}
              rows={minLines ?? 3}
              {...(props as React.TextareaHTMLAttributes<HTMLTextAreaElement>)}
              onChange={(e) => {
                onChanged?.(e.target.value);
                (
                  props as React.TextareaHTMLAttributes<HTMLTextAreaElement>
                ).onChange?.(e);
              }}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) onEditingComplete?.();
              }}
              className={cn(
                "flex w-full rounded-md bg-background px-3 py-2 text-sm",
                "ring-offset-background placeholder:text-muted-foreground",
                !hasBorderOverride &&
                  "border border-input focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                hasBorderOverride && "outline-none",
                "disabled:cursor-not-allowed disabled:opacity-50",
                prefixIcon && "pl-10",
                suffixIcon && "pr-10",
                errorText &&
                  !hasBorderOverride &&
                  "border-destructive focus-visible:ring-destructive",
              )}
              style={{
                ...sharedStyle,
                ...borderStyle,
                ...textStyle,
                resize: "vertical",
              }}
            />
          ) : (
            <Input
              id={inputId}
              ref={ref}
              placeholder={hintText}
              type={inputType}
              readOnly={readOnly}
              disabled={!enabled}
              autoFocus={autofocus}
              maxLength={maxLength}
              onChange={(e) => onChanged?.(e.target.value)}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  onEditingComplete?.();
                  onFieldSubmitted?.((e.target as HTMLInputElement).value);
                }
              }}
              className={cn(
                !hasBorderOverride &&
                  "border border-input focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                hasBorderOverride && "outline-none border-none",
                prefixIcon || prefixText ? "pl-10" : undefined,
                suffixIcon || suffixText ? "pr-10" : undefined,
                errorText &&
                  !hasBorderOverride &&
                  "border-destructive focus-visible:ring-destructive",
              )}
              style={{ ...sharedStyle, ...borderStyle, ...textStyle }}
              {...props}
            />
          )}

          {suffixText && (
            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">
              {suffixText}
            </span>
          )}
          {suffixIcon && !suffixText && (
            <div className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
              {suffixIcon}
            </div>
          )}
        </div>
        {errorText && (
          <p className="text-xs font-medium text-destructive">{errorText}</p>
        )}
        {!errorText && helperText && (
          <p className="text-xs text-muted-foreground">{helperText}</p>
        )}
        {maxLength !== undefined && (
          <p className="text-xs text-muted-foreground text-right">
            {String(props.value ?? "").length}/{maxLength}
          </p>
        )}
      </div>
    );
  },
);

TextField.displayName = "TextField";

import * as React from "react";
import { cn } from "../utils";
import type { Color } from "./flutter-style";

// ─── Variant presets (like Flutter's Theme.of(context).textTheme) ────────────
type TextVariant =
  | "displayLarge" // 57px
  | "displayMedium" // 45px
  | "displaySmall" // 36px
  | "headlineLarge" // 32px
  | "headlineMedium" // 28px
  | "headlineSmall" // 24px
  | "titleLarge" // 22px
  | "titleMedium" // 16px, medium weight
  | "titleSmall" // 14px, medium weight
  | "bodyLarge" // 16px
  | "bodyMedium" // 14px  (default)
  | "bodySmall" // 12px
  | "labelLarge" // 14px, medium weight
  | "labelMedium" // 12px, medium weight
  | "labelSmall" // 11px, medium weight
  // Legacy aliases for backwards compat
  | "h1"
  | "h2"
  | "h3"
  | "h4"
  | "large"
  | "small"
  | "muted"
  | "p";

type TextOverflow = "ellipsis" | "clip" | "visible" | "fade";
type TextAlign = "left" | "center" | "right" | "justify" | "start" | "end";
type FontStyle = "normal" | "italic";
type TextDecoration = "none" | "underline" | "line-through" | "overline";
type FontWeight =
  | "thin"
  | "extraLight"
  | "light"
  | "normal"
  | "medium"
  | "semiBold"
  | "bold"
  | "extraBold"
  | "black"
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900;

export interface TextProps extends React.HTMLAttributes<HTMLElement> {
  /** Semantic/style preset. Mirrors Flutter's TextTheme variants. Default "bodyMedium". */
  variant?: TextVariant;
  /** Override the rendered HTML element. */
  as?: keyof JSX.IntrinsicElements;

  // ── Direct TextStyle props (no TextStyle object needed) ──────────────────

  /** Font size in px or any CSS unit string. */
  fontSize?: number | string;
  /** Font weight. Accepts Flutter-style names or numeric values. */
  fontWeight?: FontWeight;
  /** Text color. */
  color?: Color;
  /** Letter spacing in px or CSS unit. */
  letterSpacing?: number | string;
  /** Line height multiplier or px/unit string. */
  lineHeight?: number | string;
  /** Text decoration. */
  decoration?: TextDecoration;
  /** How to handle text that overflows. */
  overflow?: TextOverflow;
  /** Whether the text wraps. false = single line. Default true. */
  softWrap?: boolean;
  /** Max number of lines before overflow applies. */
  maxLines?: number;
  /** Text alignment. */
  textAlign?: TextAlign;
  /** Font style. */
  fontStyle?: FontStyle;
  /** Opacity (0.0–1.0). */
  opacity?: number;

  key?: React.Key;
}

// ─── Font weight name → CSS value ────────────────────────────────────────────
const fontWeightMap: Record<string, string> = {
  thin: "100",
  extraLight: "200",
  light: "300",
  normal: "400",
  medium: "500",
  semiBold: "600",
  bold: "700",
  extraBold: "800",
  black: "900",
};

const resolveFontWeight = (w?: FontWeight): string | undefined => {
  if (w === undefined) return undefined;
  if (typeof w === "number") return String(w);
  return fontWeightMap[w] ?? String(w);
};

// ─── Variant → Tailwind base classes ─────────────────────────────────────────
const variantClasses: Record<TextVariant, string> = {
  displayLarge: "text-[57px] font-light tracking-[-0.25px]",
  displayMedium: "text-[45px] font-light",
  displaySmall: "text-[36px] font-normal",
  headlineLarge: "text-[32px] font-normal",
  headlineMedium: "text-[28px] font-normal",
  headlineSmall: "text-2xl font-normal",
  titleLarge: "text-[22px] font-normal",
  titleMedium: "text-base font-medium tracking-[0.15px]",
  titleSmall: "text-sm font-medium tracking-[0.1px]",
  bodyLarge: "text-base font-normal tracking-[0.5px]",
  bodyMedium: "text-sm font-normal tracking-[0.25px]",
  bodySmall: "text-xs font-normal tracking-[0.4px]",
  labelLarge: "text-sm font-medium tracking-[0.1px]",
  labelMedium: "text-xs font-medium tracking-[0.5px]",
  labelSmall: "text-[11px] font-medium tracking-[0.5px]",
  // Legacy aliases
  h1: "scroll-m-20 text-4xl font-extrabold tracking-tight lg:text-5xl",
  h2: "scroll-m-20 border-b pb-2 text-3xl font-semibold tracking-tight first:mt-0",
  h3: "scroll-m-20 text-2xl font-semibold tracking-tight",
  h4: "scroll-m-20 text-xl font-semibold tracking-tight",
  p: "leading-7 [&:not(:first-child)]:mt-6",
  large: "text-lg font-semibold",
  small: "text-sm font-medium leading-none",
  muted: "text-sm text-muted-foreground",
};

// Default HTML tag per variant
const variantTag: Partial<Record<TextVariant, keyof JSX.IntrinsicElements>> = {
  h1: "h1",
  h2: "h2",
  h3: "h3",
  h4: "h4",
  displayLarge: "h1",
  displayMedium: "h1",
  displaySmall: "h2",
  headlineLarge: "h2",
  headlineMedium: "h3",
  headlineSmall: "h3",
  titleLarge: "h4",
  titleMedium: "h5",
  titleSmall: "h6",
};

// Overflow → CSS
const overflowStyle = (
  overflow?: TextOverflow,
  softWrap?: boolean,
  maxLines?: number,
): React.CSSProperties => {
  const noWrap = softWrap === false || maxLines === 1;
  const css: React.CSSProperties = {};

  if (noWrap || maxLines) {
    css.overflow = "hidden";
    if (overflow === "ellipsis" || (!overflow && (noWrap || maxLines))) {
      css.textOverflow = "ellipsis";
    }
    if (noWrap) {
      css.whiteSpace = "nowrap";
    } else if (maxLines && maxLines > 1) {
      css.display = "-webkit-box";
      (css as Record<string, unknown>)["-webkit-line-clamp"] = maxLines;
      (css as Record<string, unknown>)["-webkit-box-orient"] = "vertical";
    }
  } else if (overflow === "clip") {
    css.overflow = "hidden";
  }

  return css;
};

/**
 * A rich text widget with Flutter-style inline styling props.
 * Equivalent to Flutter's Text() widget with TextStyle applied directly.
 *
 * @example
 * <Text fontSize={20} fontWeight="bold" color={AppColors.primary} maxLines={2} overflow="ellipsis">
 *   Hello world
 * </Text>
 */
export const Text = React.forwardRef<HTMLElement, TextProps>(
  (
    {
      variant = "bodyMedium",
      as,
      fontSize,
      fontWeight,
      color,
      letterSpacing,
      lineHeight,
      decoration,
      overflow,
      softWrap,
      maxLines,
      textAlign,
      fontStyle,
      opacity,
      className,
      style,
      ...props
    },
    ref,
  ) => {
    const Tag = (as ?? variantTag[variant] ?? "p") as React.ElementType;

    const inlineStyle: React.CSSProperties = {
      fontSize:
        fontSize !== undefined
          ? typeof fontSize === "number"
            ? `${fontSize}px`
            : fontSize
          : undefined,
      fontWeight: resolveFontWeight(fontWeight),
      color,
      letterSpacing:
        letterSpacing !== undefined
          ? typeof letterSpacing === "number"
            ? `${letterSpacing}px`
            : letterSpacing
          : undefined,
      lineHeight:
        lineHeight !== undefined
          ? typeof lineHeight === "number"
            ? lineHeight
            : lineHeight
          : undefined,
      textDecoration: decoration,
      textAlign,
      fontStyle,
      opacity,
      ...overflowStyle(overflow, softWrap, maxLines),
      ...style,
    };

    return (
      <Tag
        // @ts-expect-error — dynamic tag ref
        ref={ref}
        className={cn("text-foreground", variantClasses[variant], className)}
        style={inlineStyle}
        {...props}
      />
    );
  },
);

Text.displayName = "Text";

import * as React from "react";
import { cn } from "../utils";

export interface TooltipProps extends React.HTMLAttributes<HTMLDivElement> {
  message: string;
  children: React.ReactNode;
  delay?: number;
  /**
   * Preferred side. "auto" flips to the bottom if there isn't enough room above the trigger.
   */
  side?: "top" | "bottom" | "auto";
  key?: React.Key;
}

const ESTIMATED_TOOLTIP_HEIGHT = 36;
const TOOLTIP_MARGIN = 8;

/**
 * A tooltip widget.
 * Equivalent to Flutter's Tooltip() widget.
 */
export const Tooltip = ({
  message,
  children,
  delay = 300,
  side = "auto",
  className,
  ...props
}: TooltipProps) => {
  const triggerRef = React.useRef<HTMLDivElement>(null);
  const [resolvedSide, setResolvedSide] = React.useState<"top" | "bottom">(
    side === "bottom" ? "bottom" : "top"
  );

  const handleMouseEnter = React.useCallback(() => {
    if (side !== "auto") {
      setResolvedSide(side);
      return;
    }
    const el = triggerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const needed = ESTIMATED_TOOLTIP_HEIGHT + TOOLTIP_MARGIN;
    const spaceAbove = rect.top;
    const spaceBelow = window.innerHeight - rect.bottom;
    if (spaceAbove >= needed) {
      setResolvedSide("top");
    } else if (spaceBelow >= needed) {
      setResolvedSide("bottom");
    } else {
      setResolvedSide(spaceAbove >= spaceBelow ? "top" : "bottom");
    }
  }, [side]);

  const isTop = resolvedSide === "top";

  return (
    <div
      ref={triggerRef}
      onMouseEnter={handleMouseEnter}
      onFocus={handleMouseEnter}
      className={cn("group relative inline-block", className)}
      {...props}
    >
      {children}
      <div
        className={cn(
          "absolute left-1/2 -translate-x-1/2 px-2 py-1 bg-slate-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 group-focus-within:opacity-100 transition-opacity duration-200 pointer-events-none whitespace-nowrap z-50 shadow-sm",
          isTop ? "bottom-full mb-2" : "top-full mt-2",
          `delay-${delay}`
        )}
      >
        {message}
        {/* Triangle Arrow */}
        <div
          className={cn(
            "absolute left-1/2 -translate-x-1/2 border-4 border-transparent",
            isTop ? "top-full border-t-slate-800" : "bottom-full border-b-slate-800"
          )}
        />
      </div>
    </div>
  );
};

import * as React from "react";
import { cn } from "../utils";

export interface VerticalDividerProps {
  /** Width (thickness) of the line in px. Default 1. */
  thickness?: number;
  /** Space above the line. Equivalent to Flutter's `indent`. Default 0. */
  indent?: number | string;
  /** Space below the line. Equivalent to Flutter's `endIndent`. Default 0. */
  endIndent?: number | string;
  /** Explicit height of the divider. If omitted it stretches to fill its parent (self-stretch). */
  height?: number | string;
  /** Color of the line. Defaults to the theme border color. */
  color?: string;
  className?: string;
  key?: React.Key;
}

/**
 * A thin vertical line, with padding on either side.
 * Equivalent to Flutter's VerticalDivider() widget.
 *
 * Place inside a Row or any flex-row container for it to stretch to full height.
 */
export const VerticalDivider = ({
  thickness = 1,
  indent = 0,
  endIndent = 0,
  height,
  color,
  className,
}: VerticalDividerProps) => {
  return (
    <div
      className={cn("self-stretch bg-border", className)}
      style={{
        width: `${thickness}px`,
        height: height !== undefined
          ? (typeof height === "number" ? `${height}px` : height)
          : undefined,
        marginTop: typeof indent === "number" ? `${indent}px` : indent,
        marginBottom: typeof endIndent === "number" ? `${endIndent}px` : endIndent,
        backgroundColor: color,
        flexShrink: 0,
      }}
      aria-hidden="true"
    />
  );
};

VerticalDivider.displayName = "VerticalDivider";

import * as React from "react";
import { cn } from "../utils";
import type { EdgeInsetsInput } from "./flutter-style";
import { edgeInsetsToStyle } from "./flutter-style";

export enum WrapAlignment {
  start = "justify-start",
  end = "justify-end",
  center = "justify-center",
  spaceBetween = "justify-between",
  spaceAround = "justify-around",
  spaceEvenly = "justify-evenly",
}

export enum WrapCrossAlignment {
  start = "items-start",
  end = "items-end",
  center = "items-center",
}

export interface WrapProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Spacing between children in the main axis. */
  spacing?: number;
  /** Spacing between lines in the cross axis. */
  runSpacing?: number;
  /** How children within a run are aligned in the main axis. */
  alignment?: WrapAlignment;
  /** How children are aligned in the cross axis within a run. */
  crossAxisAlignment?: WrapCrossAlignment;
  /** Padding around the Wrap. */
  padding?: EdgeInsetsInput;
  /** Direction of the wrap. */
  direction?: "horizontal" | "vertical";
  key?: React.Key;
}

/**
 * A widget that displays its children in multiple horizontal or vertical runs.
 * Equivalent to Flutter's Wrap() widget.
 */
export const Wrap = React.forwardRef<HTMLDivElement, WrapProps>(
  (
    {
      spacing = 0,
      runSpacing = 0,
      alignment = WrapAlignment.start,
      crossAxisAlignment = WrapCrossAlignment.start,
      padding,
      direction = "horizontal",
      children,
      className,
      style,
      ...props
    },
    ref,
  ) => {
    return (
      <div
        ref={ref}
        className={cn(
          "flex flex-wrap",
          direction === "vertical" ? "flex-col" : "flex-row",
          alignment,
          crossAxisAlignment,
          className,
        )}
        style={{
          // CSS gap shorthand: "<row-gap> <column-gap>"
          // runSpacing = gap between runs (rows)  → row-gap
          // spacing    = gap between items in a run → column-gap
          gap: `${runSpacing}px ${spacing}px`,
          ...edgeInsetsToStyle(padding, "padding"),
          ...style,
        }}
        {...props}
      >
        {children}
      </div>
    );
  },
);

Wrap.displayName = "Wrap";

export const formatDate = (dateInput?: string | Date) => {
  if (!dateInput) return "";
  const date =
    typeof dateInput === "string"
      ? new Date(dateInput.replace(" ", "T") + "Z")
      : dateInput;

  const now = new Date();
  const diffInHours = (now.getTime() - date.getTime()) / (1000 * 60 * 60);

  if (diffInHours > 24) {
    return date.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
    });
  }
  return date.toLocaleTimeString(undefined, {
    hour: "2-digit",
    minute: "2-digit",
  });
};
